## 🏗️ 技术方案

### 方案一：轻量级自研方案（推荐）

**优势**:
- ✅ 无外部依赖
- ✅ 完全控制
- ✅ 体积小（<200 行代码）
- ✅ 易于维护

**核心实现**:

```typescript
// database/migrate.ts
import { Pool } from 'pg';
import * as fs from 'fs';
import * as path from 'path';

interface Migration {
  version: number;
  name: string;
  upSQL: string;
  downSQL: string;
}

export class PostgresMigrator {
  private pool: Pool;
  private migrationsPath: string;

  constructor(config: { connectionString: string; migrationsPath: string }) {
    this.pool = new Pool({ connectionString: config.connectionString });
    this.migrationsPath = config.migrationsPath;
  }

  /**
   * 初始化迁移表
   */
  async init(): Promise<void> {
    await this.pool.query(`
      CREATE TABLE IF NOT EXISTS schema_migrations (
        version INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        applied_at TIMESTAMP NOT NULL DEFAULT NOW(),
        rollback_sql TEXT
      );
    `);
  }

  /**
   * 获取所有迁移文件
   */
  private getMigrations(): Migration[] {
    const files = fs.readdirSync(this.migrationsPath)
      .filter(f => f.endsWith('.up.sql'))
      .sort();

    return files.map(file => {
      const version = parseInt(file.split('_')[0]);
      const name = file.replace(`${version}_`, '').replace('.up.sql', '');
      const upSQL = fs.readFileSync(path.join(this.migrationsPath, file), 'utf-8');
      const downSQL = fs.readFileSync(
        path.join(this.migrationsPath, `${version}_${name}.down.sql`),
        'utf-8'
      );

      return { version, name, upSQL, downSQL };
    });
  }

  /**
   * 获取已应用的迁移版本
   */
  async getAppliedVersions(): Promise<number[]> {
    const result = await this.pool.query(
      'SELECT version FROM schema_migrations ORDER BY version'
    );
    return result.rows.map(row => row.version);
  }

  /**
   * 应用所有待应用的迁移
   */
  async migrate(): Promise<void> {
    await this.init();

    const migrations = this.getMigrations();
    const appliedVersions = await this.getAppliedVersions();

    for (const migration of migrations) {
      if (appliedVersions.includes(migration.version)) {
        console.log(`✓ Skipping migration ${migration.version}: ${migration.name}`);
        continue;
      }

      console.log(`↑ Applying migration ${migration.version}: ${migration.name}`);

      const client = await this.pool.connect();
      try {
        await client.query('BEGIN');
        await client.query(migration.upSQL);
        await client.query(
          'INSERT INTO schema_migrations (version, name, rollback_sql) VALUES ($1, $2, $3)',
          [migration.version, migration.name, migration.downSQL]
        );
        await client.query('COMMIT');
        console.log(`✓ Applied migration ${migration.version}`);
      } catch (error) {
        await client.query('ROLLBACK');
        console.error(`✗ Failed to apply migration ${migration.version}:`, error);
        throw error;
      } finally {
        client.release();
      }
    }

    console.log('\n✅ All migrations applied successfully!');
  }

  /**
   * 回滚指定数量的迁移
   */
  async rollback(count: number = 1): Promise<void> {
    await this.init();

    const client = await this.pool.connect();
    try {
      const result = await client.query(
        'SELECT version, name, rollback_sql FROM schema_migrations ORDER BY version DESC LIMIT $1',
        [count]
      );

      for (const row of result.rows) {
        console.log(`↓ Rolling back migration ${row.version}: ${row.name}`);

        await client.query('BEGIN');
        await client.query(row.rollback_sql);
        await client.query('DELETE FROM schema_migrations WHERE version = $1', [row.version]);
        await client.query('COMMIT');
        console.log(`✓ Rolled back migration ${row.version}`);
      }

      console.log('\n✅ Rollback completed!');
    } catch (error) {
      await client.query('ROLLBACK');
      console.error('✗ Rollback failed:', error);
      throw error;
    } finally {
      client.release();
    }
  }

  /**
   * 查看迁移状态
   */
  async status(): Promise<void> {
    await this.init();

    const migrations = this.getMigrations();
    const appliedVersions = await this.getAppliedVersions();

    console.log('\n📊 Migration Status:\n');
    console.log('Status   Version Name');
    console.log('───────  ─────── ────');

    for (const migration of migrations) {
      const status = appliedVersions.includes(migration.version) ? '✓ Applied' : '⊘ Pending';
      console.log(`${status}  ${String(migration.version).padStart(6)}  ${migration.name}`);
    }
  }

  /**
   * 创建新的迁移文件
   */
  create(name: string): void {
    const version = Date.now();
    const upFile = path.join(this.migrationsPath, `${version}_${name}.up.sql`);
    const downFile = path.join(this.migrationsPath, `${version}_${name}.down.sql`);

    fs.writeFileSync(upFile, `-- Migration: ${name}\n-- Up SQL\n`);
    fs.writeFileSync(downFile, `-- Migration: ${name}\n-- Down SQL\n`);

    console.log(`✓ Created migration files:`);
    console.log(`  - ${upFile}`);
    console.log(`  - ${downFile}`);
  }

  async close(): Promise<void> {
    await this.pool.end();
  }
}

// CLI 入口
async function main() {
  const command = process.argv[2];
  const arg = process.argv[3];

  const migrator = new PostgresMigrator({
    connectionString: process.env.DATABASE_URL || 'postgresql://localhost:5432/ai_team_system',
    migrationsPath: path.join(__dirname, 'postgresql', 'migrations')
  });

  try {
    switch (command) {
      case 'migrate':
        await migrator.migrate();
        break;
      case 'rollback':
        await migrator.rollback(arg ? parseInt(arg) : 1);
        break;
      case 'status':
        await migrator.status();
        break;
      case 'create':
        if (!arg) throw new Error('Migration name required');
        migrator.create(arg);
        break;
      default:
        console.log(`
Usage: npm run db [command] [args]

Commands:
  migrate              Apply all pending migrations
  rollback [count]     Rollback N migrations (default: 1)
  status               Show migration status
  create <name>        Create new migration files

Examples:
  npm run db migrate
  npm run db rollback 2
  npm run db status
  npm run db create add_user_table
        `);
    }
  } finally {
    await migrator.close();
  }
}

if (require.main === module) {
  main().catch(console.error);
}

export { PostgresMigrator };
```

